mapper.select:
SELECT * FROM hourly_report r1
WHERE r1.day_offset = #{dayOffset}
AND r1.base_time = (
    SELECT MAX(r2.base_time)
    FROM hourly_report r2
    WHERE r2.inverter_id = r1.inverter_id
    AND r2.day_offset = #{dayOffset}
)

SELECT * FROM hourly_report
WHERE day_offset = #{dayOffset}
AND base_time BETWEEN #{start} AND #{end}
ORDER BY base_time ASC
